import { Link } from 'react-router-dom';

export default function Navbar() {
  return (
    <nav className="flex items-center gap-6 px-8 py-4 bg-white shadow-sm font-sans">
      <span className="font-bold text-lg text-blue-700">SHPE Austin</span>
      <Link to="/" className="text-gray-600 hover:text-blue-700 transition-colors">Home</Link>
      <Link to="/shpe-hat" className="text-gray-600 hover:text-blue-700 transition-colors">Hat Animation</Link>
    </nav>
  );
}
